def validate_pickle_header(data: bytes) -> bool:
    """
    Basic validation that the data looks like a valid pickle stream.
    Checks for pickle protocol header bytes.
    """
    if len(data) < 2:
        return False
    # Pickle protocol 2+ starts with \x80\x0N where N is the protocol version
    if data[0] == 0x80 and data[1] in range(0, 6):
        return True
    # Protocol 0 and 1 don't have the header, but start with specific opcodes
    if data[0] in (ord('('), ord(']'), ord('}'), ord('c'), ord('i'), 0x80):
        return True
    return False


